# Custom APM processor to sanitize sensitive data
def sanitize_processor(client, event):
    """Remove sensitive data from APM events"""
    if 'context' in event:
        context = event['context']
        
        # Sanitize request data
        if 'request' in context:
            req = context['request']
            
            # Remove sensitive headers
            if 'headers' in req:
                sensitive_headers = ['authorization', 'cookie', 'x-api-key', 'x-auth-token']
                for header in sensitive_headers:
                    if header in req['headers']:
                        req['headers'][header] = '[REDACTED]'
            
            # Sanitize cookies
            if 'cookies' in req:
                req['cookies'] = {k: '[REDACTED]' for k in req['cookies']}
        
        # Sanitize user data
        if 'user' in context:
            user = context['user']
            if 'email' in user:
                # Hash email for privacy
                user['email'] = hashlib.sha256(user['email'].encode()).hexdigest()[:16]
    
    return event


# Register processor
