# API Routes
@app.route('/api/register', methods=['POST'])
def register():
    apm.client.begin_transaction('request')
    
    try:
        data = request.get_json()
        
        if not data:
            return jsonify({'error': 'Invalid request data'}), 400
        
        username = InputValidator.sanitize_string(data.get('username', ''))
        email = InputValidator.sanitize_string(data.get('email', ''))
        password = data.get('password', '')
        
        # Validate inputs
        if not InputValidator.validate_username(username):
            return jsonify({'error': 'Invalid username format'}), 400
        
        if not InputValidator.validate_email(email):
            return jsonify({'error': 'Invalid email format'}), 400
        
        if not InputValidator.validate_password(password):
            return jsonify({'error': 'Password must be at least 8 characters with uppercase, lowercase, and digit'}), 400
        
        # Check for existing user
        if User.query.filter_by(username=username).first():
            return jsonify({'error': 'Username already exists'}), 409
        
        if User.query.filter_by(email=email).first():
            return jsonify({'error': 'Email already exists'}), 409
        
        # Create user
        user = User(username=username, email=email)
        user.set_password(password)
        
        db.session.add(user)
        db.session.commit()
        
        log_audit('register', 'user', success=True)
        
        apm.client.end_transaction('register', 'success')
        
        return jsonify({
            'message': 'User registered successfully',
            'user_id': user.id
        }), 201
        
    except Exception as e:
        db.session.rollback()
        logger.error(f'Registration error: {str(e)}')
        apm.client.capture_exception()
        apm.client.end_transaction('register', 'failure')
        return jsonify({'error': 'Registration failed'}), 500


@app.route('/api/login', methods=['POST'])
def login():
    apm.client.begin_transaction('request')
    
    try:
        data = request.get_json()
        
        if not data:
            return jsonify({'error': 'Invalid request data'}), 400
        
        username = InputValidator.sanitize_string(data.get('username', ''))
        password = data.get('password', '')
        
        if not username or not password:
            return jsonify({'error': 'Username and password required'}), 400
        
        user = User.query.filter_by(username=username, is_active=True).first()
        
        if not user or not user.check_password(password):
            log_audit('login', 'user', success=False)
            apm.client.end_transaction('login', 'failure')
            return jsonify({'error': 'Invalid credentials'}), 401
        
        token = TokenManager.generate_token(user.id)
        
        log_audit('login', 'user', success=True)
        
        apm.client.set_user_context(user_id=user.id, username=user.username)
        apm.client.end_transaction('login', 'success')
        
        return jsonify({
            'token': token,
            'user_id': user.id,
            'username': user.username
        }), 200
        
    except Exception as e:
        logger.error(f'Login error: {str(e)}')
        apm.client.capture_exception()
        apm.client.end_transaction('login', 'failure')
        return jsonify({'error': 'Login failed'}), 500


