@app.route('/api/audit-logs', methods=['GET'])
@require_auth
def get_audit_logs():
    apm.client.begin_transaction('request')
    
    try:
        # Validate pagination parameters
        page = request.args.get('page', 1, type=int)
        per_page = request.args.get('per_page', 20, type=int)
        
        # Enforce limits
        page = max(1, min(page, 1000))
        per_page = max(1, min(per_page, 100))
        
        # Query with pagination
        logs = AuditLog.query.filter_by(user_id=g.current_user.id)\
            .order_by(AuditLog.timestamp.desc())\
            .paginate(page=page, per_page=per_page, error_out=False)
        
        log_audit('view', 'audit_logs', success=True)
        
        apm.client.end_transaction('get_audit_logs', 'success')
        
        return jsonify({
            'logs': [{
                'id': log.id,
                'action': log.action,
                'resource': log.resource,
                'timestamp': log.timestamp.isoformat(),
                'success': log.success
            } for log in logs.items],
            'total': logs.total,
            'page': page,
            'per_page': per_page
        }), 200
        
    except Exception as e:
        logger.error(f'Audit log retrieval error: {str(e)}')
        apm.client.capture_exception()
        apm.client.end_transaction('get_audit_logs', 'failure')
        return jsonify({'error': 'Failed to retrieve audit logs'}), 500


